// =============================================================================
// Validate the incoming PDF URL — pure-regex parsing (no `URL` constructor;
// n8n's Code-node sandbox does not expose the WHATWG URL global).
// =============================================================================

const input = $input.first().json || {};

function findUrlString(obj) {
  if (obj === null || obj === undefined) return null;
  if (typeof obj === 'string') {
    const s = obj.trim();
    if (/^https?:\/\//i.test(s) || /^\/\//.test(s) || /\.pdf(\?|#|$)/i.test(s)) return s;
    return null;
  }
  if (typeof obj !== 'object') return null;
  const preferred = ['pdf_url', 'url', 'link', 'href', 'pdfUrl'];
  for (const key of preferred) {
    if (key in obj) {
      const found = findUrlString(obj[key]);
      if (found) return found;
    }
  }
  for (const key in obj) {
    if (preferred.includes(key)) continue;
    const found = findUrlString(obj[key]);
    if (found) return found;
  }
  return null;
}

let pdf_url = findUrlString(input);
if (!pdf_url) {
  throw new Error('No URL found in request. Input: ' + JSON.stringify(input).slice(0, 500));
}
pdf_url = String(pdf_url).trim();

// Normalise protocol.
if (pdf_url.startsWith('//')) {
  pdf_url = 'https:' + pdf_url;
} else if (!/^https?:\/\//i.test(pdf_url)) {
  if (pdf_url.startsWith('/')) {
    throw new Error('URL must be absolute. Received: ' + pdf_url);
  }
  pdf_url = 'https://' + pdf_url;
}

// Regex-parse the URL components.
const match = pdf_url.match(/^(https?):\/\/([^\/?#]+)(\/[^?#]*)/i);
if (!match) {
  throw new Error('Could not parse URL components from: ' + pdf_url);
}
const protocol = match[1].toLowerCase();
const hostname = match[2].toLowerCase();
const pathname = match[3];

if (protocol !== 'http' && protocol !== 'https') {
  throw new Error('Unsupported protocol: ' + protocol);
}

const allowedHosts = ['bseindia.com', 'nseindia.com'];
const hostnameAllowed = allowedHosts.some(
  h => hostname === h || hostname.endsWith('.' + h)
);
if (!hostnameAllowed) {
  throw new Error('URL must be from BSE or NSE. Got host: ' + hostname);
}

if (!pathname.toLowerCase().endsWith('.pdf')) {
  throw new Error('URL must point to a .pdf file. Got path: ' + pathname);
}

// Per-request model override (whitelisted) so the frontend can fall back from
// pro -> flash when a slow PDF would otherwise hit Vercel's 60s function cap.
// The webhook passes the JSON body as a top-level object or under `body` —
// check both shapes so callers can pass `{ model: ... }` either way.
const allowedModels = ['gemini-2.5-pro', 'gemini-2.5-flash', 'gemini-2.5-flash-lite'];
const rawModel = (input.model || input.body?.model || '').toString().trim();
let model = allowedModels.includes(rawModel) ? rawModel : ($env.GEMINI_MODEL || 'gemini-2.5-pro');

return [{
  json: {
    pdf_url,
    host: hostname,
    model,
    received_at: new Date().toISOString()
  }
}];

// =============================================================================
// Prepare the Gemini request body.
// We send the PDF inline as base64 (Gemini natively accepts application/pdf).
//
// The full system prompt lives below so the workflow is self-contained.
// Update Section 3 of the assignment, mirror it here, and the prompt stays
// version-controlled with the workflow.
// =============================================================================

const item = $input.first();
const binaryData = item.binary?.data;
if (!binaryData) {
  throw new Error('PDF download returned no binary data.');
}

// n8n stores HTTP-downloaded binary via filesystem-v2 by default — binaryData.data
// is a reference string, not the actual base64. The helper resolves the real bytes.
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const pdf_base64 = buffer.toString('base64');
const pdf_bytes = buffer.length;
const size_mb = pdf_bytes / 1024 / 1024;

if (size_mb > 20) {
  throw new Error('PDF too large (' + size_mb.toFixed(2) + ' MB). Limit is 20 MB.');
}

const prompt = `You are a financial data processor that converts quarterly P&L statements into standardized JSON format. You are only to look at the consolidated financial results.

The table can be under any form including but not limited 'FINANCIAL RESULTS FOR THE QUARTER / YEAR ENDED', 'STATEMENT OF AUDITED/UNADUITED CONSOLIDATED FINANCIAL RESULTS FOR THE HALF YEAR ENDED AND YEAR ENDED MARCH', 'CONSOLIDATED FINANCIAL RESULTS FOR THE QUARTER', 'Profit and Loss statement', 'PnL', 'Statement of Audited Financial Results for the Half Year & Year ended' and so on.

Critical: Look and process the standalone statement only and only if consolidated statement is not present.

Important: If you don't find the profit and loss statement in the document just output no pnl found and nothing else.

## 1. DATA EXTRACTION RULES
Company Name Extraction
1. **Identify:** Look for legal entity markers ("Limited", "Ltd", "Pvt", "Inc").
2. **Formatting:**
* Use Title Case for names (e.g., "Tata Motors").
* Keep acronyms ALL CAPS (e.g., "ITC Limited", "H.G. Infra").
* If no name is found, output: "Unknown Company"

## OUTPUT FORMAT (STRICT)
Return ONLY valid JSON with no explanations.

### CRITICAL: Column count depends on the quarter type:

**For Q1 and Q3** - output 4 columns per row (Particulars + 3 data columns):
{
  "company_name": "Tata Motors",
  "quarter_type": "standard",
  "row1": ["Particulars", "Q1 FY26", "Q4 FY25", "Q1 FY25"],
  "row2": ["Revenue", "3611.02", "3347.70", "4132.67"],
  ...
}

**For Q2** - output 6 columns per row (Particulars + 5 data columns, adding H1 of current and previous year):
{
  "company_name": "Tata Motors",
  "quarter_type": "extended",
  "row1": ["Particulars", "Q2 FY26", "Q1 FY26", "Q2 FY25", "H1 FY26", "H1 FY25"],
  "row2": ["Revenue", "450.50", "425.30", "380.20", "875.80", "740.50"],
  ...
}

**For Q4** - output 6 columns per row (Particulars + 5 data columns, adding full year current and previous year):
{
  "company_name": "Tata Motors",
  "quarter_type": "extended",
  "row1": ["Particulars", "Q4 FY26", "Q3 FY26", "Q4 FY25", "FY26", "FY25"],
  "row2": ["Revenue", "450.50", "425.30", "380.20", "1800.00", "1650.00"],
  ...
}

## TABLE STRUCTURE

### Column Headers
- Column 1: "Particulars"
- Column 2: Most recent quarter
- Column 3: Previous consecutive quarter
- Column 4: Same quarter from previous year
- Column 5 (Q2/Q4 only): H1 current year (Q2) OR Full Year current (Q4)
- Column 6 (Q2/Q4 only): H1 previous year (Q2) OR Full Year previous (Q4)

### Quarter Naming Convention
- 30-Jun-25 -> Q1 FY26
- 30-Sep-25 -> Q2 FY26
- 31-Dec-25 -> Q3 FY26
- 31-Mar-26 -> Q4 FY26

### Row Order (Standard P&L)
1. Revenue
2. Expenses (leave values blank - heading only)
3. [Expense line items - varies by company]
4. Gross Profit*
5. Gross Profit Margin*
6. Employee Benefit Expense
7. [Other operating expenses - varies]
8. Other expenses
9. Total Expenses*
10. EBITDA*
11. EBITDA Margin*
12. Depreciation
13. Finance Cost
14. Profit before Exceptional Items, Other Income*
15. Other Income
16. [Exceptional items - if present]
17. [Share of profit/loss in JV/Associate - if present]
18. Profit/Loss Before Tax*
19. Tax Expenses
20. PAT*
21. PAT Margin*
22. EPS (Basic)

*Calculated if missing

You are required to look at the given data and intelligently add or remove fields.

Note:
1. Service charges/Service Cost are not included in the gross profit calculation.
2. Revenue is revenue from operations and not total revenue.
3. If excise duty is present then there will be a net revenue = revenue - excise duty.
4. Make sure that the values you pick and output are of the correct quarters.

## CALCULATION FORMULAS
**Gross Profit** = Revenue - COGS-type expenses
**Gross Profit Margin** = (Gross Profit / Revenue) x 100
**Total Expenses** = Sum of all expense line items (excluding Depreciation and Finance Cost)
**EBITDA** = Revenue - Total Operating Expenses (excluding Depreciation, Finance Cost and other income)
**EBITDA Margin** = (EBITDA / Revenue) x 100
**Profit before Exceptional Items, Other Income** = EBITDA - Depreciation - Finance Cost
**Profit Before Tax** = EBITDA - Depreciation - Finance Cost + Other Income +/- Exceptional items +/- Share of profit/loss in JV
**PAT** = Profit Before Tax - Tax Expenses
**PAT Margin** = (PAT / Revenue) x 100
**EPS (Basic)** = Use provided value only; do not calculate

For Q2 and Q4, apply the same calculation formulas to the H1/FY columns.

## DATA PROCESSING RULES
- Convert ALL values to Rs Crores
- Round to 2 decimal places
- Treat "-" or null as 0 (except for EPS)
- Add "%" suffix to all margin calculations
- All numeric values must be strings in JSON
- Verify all calculations before final output`;

const geminiBody = {
  contents: [{
    parts: [
      { text: prompt },
      {
        inline_data: {
          mime_type: 'application/pdf',
          data: pdf_base64
        }
      }
    ]
  }],
  generationConfig: {
    temperature: 0.1,
    responseMimeType: 'application/json',
    maxOutputTokens: 8192
  }
};

return [{
  json: {
    gemini_body: geminiBody,
    size_mb: size_mb.toFixed(2),
    prompt_length: prompt.length
  }
}];

// =============================================================================
// Parse Gemini's response.
//
// Failure modes we still handle locally (no second Gemini call):
//   * Top-level ARRAY of rows instead of {row1, row2, ...}. Re-projected.
//   * Explicit "no pnl found" literal — surfaced as a non-success response.
//
// We deliberately do NOT retry Gemini here:
//   * Default model is gemini-2.5-pro, which is reliable enough that retries
//     rarely change the answer.
//   * Pro + Pro retry routinely pushes past Vercel's 60s function cap.
//   * The frontend retries on infrastructure errors (5xx / empty body), so we
//     don't need a second swing inside the workflow.
// =============================================================================

const REQUIRED_FIELDS = ['company_name', 'quarter_type', 'row1'];

function rawTextOf(response) {
  if (!response) throw new Error('Gemini call returned no response payload.');
  if (response.error) {
    throw new Error('Gemini API error: ' + (response.error.message || JSON.stringify(response.error)));
  }
  const candidates = response.candidates;
  if (!candidates || candidates.length === 0) {
    throw new Error('Gemini returned no candidates. Possible safety block.');
  }
  return {
    text: candidates[0]?.content?.parts?.[0]?.text?.trim() || '',
    candidate: candidates[0]
  };
}

function tryParseJson(rawText) {
  if (!rawText) return null;
  const cleaned = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  try { return JSON.parse(cleaned); }
  catch (e) { return null; }
}

function isNoPnl(rawText, parsed) {
  // Strip all non-word chars (quotes, code fences, punctuation, &, brackets,
  // etc.) and collapse whitespace, then look for any of: "no pnl found",
  // "no p l found" (when & gets stripped), "no profit loss" prefix.
  // Catches every shape we have observed: "no pnl found", ```json\n"no pnl found"```,
  // "No P&L found", 'no pnl found.', etc.
  function norm(s) {
    return String(s || '')
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  }
  const candidates = [rawText, parsed];
  for (const c of candidates) {
    const n = norm(c);
    if (!n) continue;
    if (/^no\s+pnl\s+found/.test(n)) return true;
    if (/^no\s+p\s+l\s+found/.test(n)) return true;
    if (/^no\s+profit\s+loss/.test(n)) return true;
  }
  return false;
}

function looksLikeRowArray(arr) {
  if (!Array.isArray(arr) || arr.length < 3) return false;
  for (const row of arr) if (!Array.isArray(row)) return false;
  const first = arr[0].map(v => String(v).toLowerCase()).join(' ');
  return /particulars|q[1-4]\s*fy|revenue/.test(first);
}

function recoverFromArrayForm(parsed) {
  if (!looksLikeRowArray(parsed)) return null;
  const out = { company_name: 'Unknown Company', quarter_type: null };
  for (let i = 0; i < parsed.length; i++) {
    out['row' + (i + 1)] = parsed[i].map(v => v == null ? '' : String(v));
  }
  out.quarter_type = (out.row1 || []).length >= 6 ? 'extended' : 'standard';
  return out;
}

function isSchemaOk(parsed) {
  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return false;
  for (const f of REQUIRED_FIELDS) {
    if (parsed[f] === undefined || parsed[f] === null) return false;
  }
  if (!Array.isArray(parsed.row1)) return false;
  const expectedCols = parsed.quarter_type === 'extended' ? 6 : 4;
  return parsed.row1.length === expectedCols;
}

const response = $input.first().json;
const { text: rawText, candidate } = rawTextOf(response);
let parsed = tryParseJson(rawText);

if (isNoPnl(rawText, parsed)) {
  return [{
    json: {
      success: false,
      reason: 'no_pnl_found',
      message: 'The document does not contain a recognizable Profit & Loss statement.'
    }
  }];
}

let arrayRecovered = false;
if (!isSchemaOk(parsed)) {
  const recoveredObj = recoverFromArrayForm(parsed);
  if (recoveredObj && isSchemaOk(recoveredObj)) {
    parsed = recoveredObj;
    arrayRecovered = true;
  }
}

if (!isSchemaOk(parsed)) {
  const sample = JSON.stringify(parsed).slice(0, 400);
  throw new Error('Gemini returned an unrecognised schema. Sample: ' + sample);
}

const usage = response.usageMetadata || {};

return [{
  json: {
    success: true,
    data: parsed,
    meta: {
      model_used: response.modelVersion || $('Validate URL').item.json.model || 'gemini-2.5-pro',
      prompt_tokens: usage.promptTokenCount || 0,
      completion_tokens: usage.candidatesTokenCount || 0,
      total_tokens: usage.totalTokenCount || 0,
      finish_reason: candidate.finishReason || 'unknown',
      array_form_recovered: arrayRecovered
    }
  }
}];

// =============================================================================
// Math validation layer.
// Recomputes margins/EBITDA/PAT-style metrics from raw rows and flags any
// discrepancies > 1 paisa. Niveshaay's analysts can't trust a JSON they don't
// re-prove, so we expose 'validation' metadata for every response.
// =============================================================================

const input = $input.first().json;

if (!input.success) {
  // Pass through non-success states (e.g., 'no_pnl_found') without validation.
  return [{ json: input }];
}

const data = input.data;
const rows = Object.entries(data)
  .filter(([k]) => /^row\d+$/.test(k))
  .sort(([a], [b]) => parseInt(a.replace('row', '')) - parseInt(b.replace('row', '')))
  .map(([, v]) => v);

const header = rows[0];
const dataCols = header.length - 1;
const issues = [];

const num = (s) => {
  if (s === '' || s === undefined || s === null) return null;
  const cleaned = String(s).replace(/%/g, '').replace(/,/g, '').trim();
  if (cleaned === '' || cleaned === '-') return 0;
  const n = parseFloat(cleaned);
  return Number.isFinite(n) ? n : null;
};

const findRow = (label) => rows.find(r => String(r[0]).trim().toLowerCase() === label.toLowerCase());

const revenue = findRow('Revenue');
const ebitda = findRow('EBITDA');
const ebitdaMargin = findRow('EBITDA Margin');
const pat = findRow('PAT');
const patMargin = findRow('PAT Margin');
const grossProfit = findRow('Gross Profit');
const gpMargin = findRow('Gross Profit Margin');

const checkMargin = (numerator, denominator, marginRow, label) => {
  if (!numerator || !denominator || !marginRow) return;
  for (let i = 1; i <= dataCols; i++) {
    const n = num(numerator[i]);
    const d = num(denominator[i]);
    const m = num(marginRow[i]);
    if (n === null || d === null || m === null || d === 0) continue;
    const expected = (n / d) * 100;
    const diff = Math.abs(expected - m);
    if (diff > 0.5) {
      issues.push({
        row: label,
        column: header[i],
        expected: expected.toFixed(2) + '%',
        got: m.toFixed(2) + '%',
        diff_pp: diff.toFixed(2)
      });
    }
  }
};

checkMargin(grossProfit, revenue, gpMargin, 'Gross Profit Margin');
checkMargin(ebitda, revenue, ebitdaMargin, 'EBITDA Margin');
checkMargin(pat, revenue, patMargin, 'PAT Margin');

return [{
  json: {
    ...input,
    validation: {
      passed: issues.length === 0,
      issues_count: issues.length,
      issues
    }
  }
}];

// =============================================================================
// Centralized error normalizer for any node that wires into this branch.
// Verbose: surfaces whatever shape the upstream error has, including any
// Gemini-side error message so the client can see what really went wrong.
// =============================================================================

const raw = $input.first().json;

let message = '';
let statusCode = 500;
let upstream = null;

if (raw && typeof raw === 'object') {
  // n8n HTTP node failures: { error: { message, statusCode, ... } }
  if (raw.error && typeof raw.error === 'object') {
    message = raw.error.message || JSON.stringify(raw.error).slice(0, 500);
    statusCode = raw.error.statusCode || raw.error.status || statusCode;
    upstream = raw.error;
  } else if (typeof raw.error === 'string') {
    message = raw.error;
    upstream = raw.error;
  } else if (raw.message) {
    message = raw.message;
    statusCode = raw.statusCode || statusCode;
    upstream = raw;
  } else {
    // No standard shape — dump what we got so we can debug.
    message = 'Pipeline error: ' + JSON.stringify(raw).slice(0, 800);
    upstream = raw;
  }
} else if (typeof raw === 'string') {
  message = raw;
} else {
  message = 'Unknown error occurred while processing the PDF.';
}

// Best-effort status code inference from the message text.
const m = String(message).toLowerCase();
if (statusCode === 500) {
  if (m.includes('invalid url') || m.includes('missing') || m.includes('not from bse')) statusCode = 400;
  else if (m.includes('too large')) statusCode = 413;
}

return [{
  json: {
    success: false,
    error: {
      message,
      status: statusCode,
      timestamp: new Date().toISOString(),
      upstream: upstream
    }
  }
}];
